DROP TABLE IF EXISTS `vocab_words`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vocab_words` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `content_block_id` bigint unsigned NOT NULL,
  `sort` smallint unsigned NOT NULL,
  `japanese` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `japanese_ruby` text COLLATE utf8mb4_unicode_ci,
  `romaji` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `english` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
